"use client";

import React, { useEffect, useState } from "react";
import {
  User,
  Mail,
  ShieldCheck,
  Calendar,
  Pencil,
  Package,
  MapPin,
  CheckCircle,
} from "lucide-react";

export default function ProfilePage() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const fetchMyProfile = async () => {
      try {
        const token = localStorage.getItem("accessToken");
        const res = await fetch("http://localhost:5000/user/myProfile", {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) throw new Error("Failed to fetch");
        const data = await res.json();
        setUser({
          name: data.user.name,
          role: data.user.role,
          email: data.user.email,
          time: data.user.createdAt,
        });
      } catch (err) {
        console.error("Fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchMyProfile();
  }, []);

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center text-gray-500 font-medium">
        Loading profile...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-12">
      {/* 1. TOP BANNER */}
      <div className="h-48 bg-gradient-to-r from-indigo-600 to-violet-700 w-full" />

      <div className="max-w-5xl mx-auto px-6">
        {/* HEADER / AVATAR SECTION */}
        <div className="relative -mt-16 flex flex-col md:flex-row md:items-end justify-between gap-6 pb-6 border-b">
          <div className="flex flex-col md:flex-row items-center md:items-end gap-5">
            <div className="w-32 h-32 rounded-2xl bg-white p-2 shadow-xl">
              <div className="w-full h-full rounded-xl bg-indigo-100 text-indigo-700 flex items-center justify-center text-4xl font-black border-2 border-indigo-50">
                {user.name[0].toUpperCase()}
              </div>
            </div>
            <div className="text-center md:text-left mb-2">
              <h1 className="text-3xl font-bold text-gray-900 leading-tight">
                {user.name}
              </h1>
              <div className="flex items-center gap-2 text-gray-500 mt-1 justify-center md:justify-start">
                <Mail size={16} />
                <span className="text-sm">{user.email}</span>
              </div>
            </div>
          </div>

          <button className="flex items-center gap-2 px-5 py-2.5 bg-white border border-gray-200 text-gray-700 rounded-xl font-semibold shadow-sm hover:bg-gray-50 hover:border-gray-300 transition-all active:scale-95">
            <Pencil size={18} className="text-indigo-600" />
            Edit Profile
          </button>
        </div>

        {/* 2. MAIN CONTENT GRID */}
        <div className="grid lg:grid-cols-3 gap-8 mt-8">
          {/* LEFT COLUMN: ACCOUNT DETAILS */}
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
              <h3 className="text-lg font-bold text-gray-900 mb-5">
                Account Details
              </h3>
              <div className="space-y-5">
                <DetailItem icon={User} label="Full Name" value={user.name} />
                <DetailItem
                  icon={ShieldCheck}
                  label="Account Role"
                  value={user.role}
                  badge
                />
                <DetailItem
                  icon={Calendar}
                  label="Member Since"
                  value="January 12, 2025"
                />
                <DetailItem icon={MapPin} label="Location" value="N/A" />
              </div>
            </div>
          </div>

          {/* RIGHT COLUMN: STATS & ACTIVITY */}
          <div className="lg:col-span-2 space-y-6">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <StatCard icon={Package} label="Lost" value="05" color="blue" />
              <StatCard
                icon={MapPin}
                label="Found"
                value="03"
                color="emerald"
              />
              <StatCard
                icon={Calendar}
                label="Claims"
                value="04"
                color="amber"
              />
              <StatCard
                icon={CheckCircle}
                label="Solved"
                value="01"
                color="indigo"
              />
            </div>

            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
              <div className="p-6 border-b border-gray-50 flex justify-between items-center">
                <h3 className="text-lg font-bold text-gray-900">
                  Recent Activity
                </h3>
                <button className="text-sm font-semibold text-indigo-600 hover:text-indigo-700">
                  View All
                </button>
              </div>
              <div className="p-6">
                <div className="flex items-center justify-center py-8 flex-col text-gray-400">
                  <Package
                    size={40}
                    strokeWidth={1.5}
                    className="mb-2 opacity-50"
                  />
                  <p className="text-sm font-medium">
                    No recent activity to display
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ===== REUSABLE SUB-COMPONENTS ===== */

/**
 * @param {React.ElementType} icon - The Lucide icon component
 */
function DetailItem({ icon: Icon, label, value, badge }) {
  return (
    <div className="flex gap-4 items-start">
      <div className="mt-1 text-gray-400">
        <Icon size={20} />
      </div>
      <div>
        <p className="text-xs font-semibold uppercase tracking-wider text-gray-400 mb-0.5">
          {label}
        </p>
        {badge ? (
          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-bold bg-indigo-50 text-indigo-700 border border-indigo-100">
            {value}
          </span>
        ) : (
          <p className="text-sm font-medium text-gray-800">{value}</p>
        )}
      </div>
    </div>
  );
}

/**
 * @param {React.ElementType} icon - The Lucide icon component
 */
function StatCard({ icon: Icon, label, value, color }) {
  const colorClasses = {
    blue: "bg-blue-50 text-blue-600",
    emerald: "bg-emerald-50 text-emerald-600",
    amber: "bg-amber-50 text-amber-600",
    indigo: "bg-indigo-50 text-indigo-600",
  };

  return (
    <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-all">
      <div
        className={`w-10 h-10 rounded-xl ${colorClasses[color]} flex items-center justify-center mb-3`}
      >
        <Icon size={20} />
      </div>
      <p className="text-2xl font-bold text-gray-900">{value}</p>
      <p className="text-xs font-medium text-gray-500 uppercase tracking-wide">
        {label}
      </p>
    </div>
  );
}
